import React from 'react';
import { FiMoon, FiSun } from 'react-icons/fi';
import { useTheme } from '../context/ThemeContext';

const Header = ({ toggleTheme }) => {
  const { theme } = useTheme();
  const heroImage = 'src/assets/pexels-jan-van-der-wolf-11680885-32239084.jpg';

  return (
    <header
      id="home"
      className="header"
      style={{ '--hero-image': `url(${heroImage})` }}
    >
      <div className="container hero-content">
        <div className="brand-lockup">
          <span className="eyebrow">Civil / Project Engineer</span>
          <h1>John Doe</h1>
          <p>Infrastructure delivery, site coordination, and technical project controls.</p>
        </div>
        <button
          className="theme-toggle"
          onClick={toggleTheme}
          aria-label="Toggle theme"
          title="Toggle theme"
        >
          {theme === 'light' ? <FiMoon aria-hidden="true" /> : <FiSun aria-hidden="true" />}
        </button>
      </div>
    </header>
  );
};

export default Header;
